fn solve(n: i64, k: i64) -> i64 {
    if k == 0 {
        return 0;
    }
    if k == 1 {
        // Numbers with popcount-depth 1 are those whose binary representation has exactly 1 bit set
        // And their value is <= n
        let mut count = 0;
        let mut power = 1;
        while power <= n {
            count += 1;
            power <<= 1;
        }
        return count;
    }

    // We need to find numbers x in [1, n] such that their popcount-depth is exactly k
    // We can use BFS to find all numbers with popcount-depth exactly k
    // We can use memoization to avoid recomputing the depth for the same number

    let mut memo = std::collections::HashMap::new();

    fn get_depth(x: i64, memo: &mut std::collections::HashMap<i64, i64>) -> i64 {
        if memo.contains_key(&x) {
            return *memo.get(&x).unwrap();
        }
        let mut depth = 0;
        let mut current = x;
        while current != 1 {
            current = current.count_ones() as i64;
            depth += 1;
            if depth > 5 { // Since k is at most 5
                break;
            }
        }
        memo.insert(x, depth);
        depth
    }

    let mut count = 0;
    for i in 1..=n {
        if get_depth(i, &mut memo) == k {
            count += 1;
        }
    }

    count
}
